#include<bits/stdc++.h>
using namespace std;
set<int> s[1000010];
int a[1000010];
int main()
{
    int n,m,ans=0;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        ans+=(a[i]!=a[i-1]);
        s[a[i]].insert(i);
    }
    while(m--)
    {
        int op,x,y;
        scanf("%d",&op);
        if(op==1)
        {
            scanf("%d%d",&x,&y);
            if(x==y)
            {
                continue;
            }
            if(s[x].size()>s[y].size())
            {
                s[x].swap(s[y]);
            }
            for(int i:s[x])
            {
                if(s[y].count(i-1))
                {
                    ans--;
                }
                if(s[y].count(i+1))
                {
                    ans--;
                }
            }
            for(int i:s[x])
            {
                s[y].insert(i);
            }
            s[x].clear();
        }
        else
        {
            printf("%d\n",ans);
        }
    }
    return 0;
}
